  ('disabled-e0adf6cd-moex-00003', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-114-decd973b', 'sub-disabled-e0adf6cd-01', NULL, 'single_choice', '依司法院大法官解釋，社會秩序維護法曾對從事性交易之行為人，僅處罰 意圖得利之一方，而不處罰支付對價之相對人的規定，違反下列何種基 本權？', '["工作權", "財產權", "平等權", "人身自由"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "303", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
