  ('disabled-e0adf6cd-moex-00005', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-114-decd973b', 'sub-disabled-e0adf6cd-01', NULL, 'single_choice', '關於司法院大法官審理案件法及憲法訴訟法，下列敘述何者正確？', '["依司法院大法官審理案件法，地方自治團體並無聲請釋憲之途徑", "依憲法訴訟法，僅最高法院法官得聲請違憲判決", "依憲法訴訟法，無憲法解釋疑義之聲請判決類型", "依司法院大法官審理案件法，立委現有總額4分之1以上，得為釋憲聲請"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "303", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
  ('disabled-e0adf6cd-moex-00006', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-114-decd973b', 'sub-disabled-e0adf6cd-01', NULL, 'single_choice', '依憲法訴訟法規定，有關憲法法庭判決宣告法規範定期失效相關之敘述， 下列何者正確？', '["因舊法規尚未失效，故各法院仍應依舊法判決，不得停止訴訟", "判決法規範定期失效者，各法院應依職權裁定停止審理程序", "審理原因案件之法院，原則上不受定期失效期限之拘束", "審理原因案件之法院，除判決主文另有諭知外，應依舊法為判決"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "303", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
